        .thenThrow(new PartitionAssignorException("Assignment failed on replacement"));

    context = new GroupMetadataManagerTestContext.Builder()
        .withConfig(GroupCoordinatorConfig.CONSUMER_GROUP_ASSIGNORS_CONFIG, List.of(assignor))
        .withMetadataImage(setupMetadataImage(topicId, "test-topic", 3))
        .build();

    // First member joins successfully
    CoordinatorResult<ConsumerGroupHeartbeatResponseData, CoordinatorRecord> joinResult =
        context.consumerGroupHeartbeat(
