                .setGroupId(groupId)
                .setMemberId(memberId2)
                .setMemberEpoch(0)
                .setGroupInstanceId(instanceId)
                .setRebalanceTimeoutMs(5000)
                .setSubscribedTopicNames(List.of("test-topic"))));

    assertTrue(thrown.getMessage().contains("Assignment failed"),
